#!/usr/bin/env python3
"""Live progress server for Steam installation monitoring."""

import http.server
import json
import re
import os

LOG_FILE = os.path.expanduser(
    "~/.gemini/antigravity-cli/brain/acdc1b23-6711-4557-8af2-96bdbfa109ef/"
    ".system_generated/tasks/task-6.log"
)
PORT = 8765
HTML_DIR = os.path.dirname(os.path.abspath(__file__))


def parse_progress():
    """Parse the apt download log for progress info."""
    result = {
        "overall_percent": 0,
        "current_package": None,
        "pkg_percent": 0,
        "speed": "--",
        "eta": "--",
        "downloaded": "--",
        "status": "downloading",
        "log_lines": [],
    }

    if not os.path.exists(LOG_FILE):
        return result

    try:
        with open(LOG_FILE, "r", errors="replace") as f:
            content = f.read()
    except Exception:
        return result

    lines = content.split("\n")

    # Collect meaningful log lines (non-progress, non-empty)
    log_lines = []
    for line in lines:
        stripped = line.strip()
        if stripped and not stripped.startswith("\r") and len(stripped) > 3:
            # Filter out pure progress bar lines
            if not re.match(r'^\d+%\s*\[', stripped):
                log_lines.append(stripped)

    result["log_lines"] = log_lines[-20:]  # last 20 lines

    # Find the latest progress line (they contain \r)
    # apt progress lines look like: "7% [17 libicu74:i386 5,923 kB/11.0 MB 54%]   129 kB/s 15min 32s"
    all_progress = []
    for line in lines:
        # Split by \r to get sub-lines
        parts = line.split("\r")
        for part in parts:
            part = part.strip()
            if re.match(r'^\d+%\s*\[', part):
                all_progress.append(part)

    if all_progress:
        latest = all_progress[-1]

        # Overall percent
        m = re.match(r'^(\d+)%', latest)
        if m:
            result["overall_percent"] = int(m.group(1))

        # Current package and its progress
        pkg_match = re.search(r'\[\d+\s+(\S+)\s+[\d,]+\s*\w*B?/[\d.]+\s*\w+B?\s+(\d+)%\]', latest)
        if pkg_match:
            result["current_package"] = pkg_match.group(1)
            result["pkg_percent"] = int(pkg_match.group(2))
        else:
            # Try simpler pattern
            pkg_match2 = re.search(r'\[\d+\s+(\S+)', latest)
            if pkg_match2:
                result["current_package"] = pkg_match2.group(1)

        # Speed
        speed_match = re.search(r'(\d+[\d,.]*\s*[kMG]?B/s)', latest)
        if speed_match:
            result["speed"] = speed_match.group(1)

        # ETA
        eta_match = re.search(r'(\d+\w*\s*\d*\w*)\s*$', latest)
        if eta_match:
            eta_val = eta_match.group(1).strip()
            if 'min' in eta_val or 's' in eta_val or 'h' in eta_val:
                result["eta"] = eta_val

        # Downloaded size from package info
        dl_match = re.search(r'([\d,]+\s*[kMG]?B)/[\d.]+\s*[kMG]?B', latest)
        if dl_match:
            result["downloaded"] = dl_match.group(1).replace(',', '')

    # Check for completion
    for line in lines[-30:]:
        if 'Setting up' in line or 'Processing triggers' in line:
            result["status"] = "installing"
            result["overall_percent"] = 100
        if 'is already the newest version' in line or 'newly installed' in line:
            result["status"] = "complete"
            result["overall_percent"] = 100

    # Check if download phase is done (100%)
    if result["overall_percent"] >= 100 and result["status"] == "downloading":
        result["status"] = "installing"

    return result


class ProgressHandler(http.server.SimpleHTTPRequestHandler):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, directory=HTML_DIR, **kwargs)

    def do_GET(self):
        if self.path == '/api/progress':
            data = parse_progress()
            self.send_response(200)
            self.send_header('Content-Type', 'application/json')
            self.send_header('Access-Control-Allow-Origin', '*')
            self.end_headers()
            self.wfile.write(json.dumps(data).encode())
        else:
            super().do_GET()

    def log_message(self, format, *args):
        pass  # Suppress request logging


if __name__ == '__main__':
    print(f"🎮 Steam Progress Dashboard running at http://localhost:{PORT}")
    server = http.server.HTTPServer(('', PORT), ProgressHandler)
    server.serve_forever()
